def solve(arg1: dict) -> list[dict]:
    project_data = {
        '123': {
            'members': [
                {'id': '1', 'name': 'Alice', 'role': 'admin'},
                {'id': '2', 'name': 'Bob', 'role': 'member'}
            ],
            'invites': [
                {'id': '1', 'email': 'invitee@example.com', 'status': 'pending'}
            ]
        }
    }

    action = arg1.get('action')
    project_id = arg1.get('projectId')

    if action == 'get_project_members':
        return project_data.get(project_id, {}).get('members', [])

    elif action == 'add_project_member':
        new_member = {'id': '3', 'name': 'Charlie', 'role': 'member'}
        project_data[project_id]['members'].append(new_member)
        return new_member

    elif action == 'get_invites':
        return project_data.get(project_id, {}).get('invites', [])

    elif action == 'accept_invite':
        invite = project_data.get(project_id, {}).get('invites', [])[0]
        if invite:
            invite['status'] = 'accepted'
            return {'status': 'accepted'}

    elif action == 'delete_member':
        project_data[project_id]['members'] = [
            member for member in project_data[project_id]['members'] if member['id'] != '1'
        ]
        return {'status': 'deleted'}

    return None
